CREATE OR REPLACE VIEW vr_bon_lon_define (account_year, membership_no, loan_contract_no, loan_type, loan_balance, loan_percent, item_amount) AS SELECT  sc_kep_cut_bonus_item.account_year
, sc_kep_cut_bonus_item.membership_no
, sc_kep_cut_bonus_item.loan_contract_no
, sc_kep_cut_bonus_item.loan_type
, sc_kep_cut_bonus_item.loan_balance
